+				Type:           "escalation",
+				Version:        1,
+				StaleThreshold: "not-a-duration",
+			},
+			wantErr: true,
+			errMsg:  "invalid stale_threshold",
+		},
+		{
+			name: "invalid severity key",
+			config: &EscalationConfig{
+				Type:    "escalation",
+				Version: 1,
+				Routes: map[string][]string{
