+			config: &EscalationConfig{
+				Type:             "escalation",
+				Version:          1,
+				MaxReescalations: -1,
+			},
+			wantErr: true,
+			errMsg:  "max_reescalations must be non-negative",
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			err := validateEscalationConfig(tt.config)
+			if tt.wantErr {
+				if err == nil {
