+		dir := t.TempDir()
+		path := filepath.Join(dir, "settings", "escalation.json")
+
+		cfg, err := LoadOrCreateEscalationConfig(path)
+		if err != nil {
+			t.Fatalf("LoadOrCreateEscalationConfig: %v", err)
+		}
+
