+			t.Fatalf("SaveEscalationConfig: %v", err)
+		}
+
+		// Load it
+		cfg, err := LoadOrCreateEscalationConfig(path)
+		if err != nil {
+			t.Fatalf("LoadOrCreateEscalationConfig: %v", err)
+		}
+
+		if cfg.StaleThreshold != "1h" {
+			t.Errorf("StaleThreshold = %q, want %q", cfg.StaleThreshold, "1h")
